+        let mut prev = std::ptr::null_mut::<NativeResolvContext>();
+        let mut current = head.get();
+        while !current.is_null() {
+            if current == target {
+                let should_free = unsafe {
+                    if (*current).__from_res && (*current).__refcount > 1 {
+                        (*current).__refcount -= 1;
+                        false
+                    } else {
